mapper.select:
SELECT t1.ID, t1.EQUIP_ID, t1.DATA_TYPE_CODE, t1.DATA_TYPE_NAME, t1.FILE_TABLE_ID, t1.REMARK, t1.CREATE_BY, t1.CREATE_BY_NAME, t1.CREATE_TIME, t1.UPDATE_BY, t1.UPDATE_BY_NAME, t1.UPDATE_TIME, t2.EQUIP_NAME, t2.EQUIP_SMALL_CATEGORY_NAME, t2.SPECIFIC_CODE, t2.MODEL_NUMBER, t3.MANUFACTURER, t4.FILE_NAME AS fileTableName, t4.BUSINESS_TYPE AS fileTableType FROM E_M_EQPT_FILE t1 LEFT JOIN E_M_EQPT_INFO t2 ON t1.EQUIP_ID = t2.ID LEFT JOIN E_M_EQPT_SUPPLY t3 ON t2.ID = t3.EQUIP_ID AND t3.DEL_FLAG = 0 LEFT JOIN SYS_FILE t4 ON t1.FILE_TABLE_ID = t4.ID
AND t1.EQUIP_ID = #{equipId}
AND t2.EQUIP_NAME LIKE #{equipNamePattern}
AND t1.DATA_TYPE_CODE LIKE #{dataTypeCodePattern}
AND t1.DATA_TYPE_NAME LIKE #{dataTypeNamePattern}
AND t1.FILE_TABLE_ID = #{fileTableId}
AND t4.FILE_NAME LIKE #{fileTableNamePattern}
ORDER BY t1.CREATE_TIME DESC
